const response = $.steps.scrapeVideo.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 10000);
const title = data.title || data.metadata?.title || '';
const url = $.input.youtubeUrl;

const videoId = url.match(/[?&]v=([^&]+)/) ? url.match(/[?&]v=([^&]+)/)[1] : url.split('/').pop();

return { markdown, title, url, videoId, contentLength: markdown.length };

const data = $.steps.extractContent.output;
const style = $.input.summaryStyle || 'detailed';

let styleInstructions = '';
if (style === 'brief') {
  styleInstructions = 'Create a brief summary with 5-8 bullet points of key takeaways. Keep it under 200 words.';
} else if (style === 'executive') {
  styleInstructions = 'Create an executive summary focused on actionable insights, business implications, and strategic takeaways. 200-300 words.';
} else {
  styleInstructions = 'Create a detailed summary covering all major topics discussed, with key quotes and examples. 300-500 words.';
}

let prompt = 'You are a content summarization expert. Summarize the following YouTube video content.\n\n';
prompt += 'VIDEO TITLE: ' + data.title + '\n';
prompt += 'VIDEO URL: ' + data.url + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + data.markdown + '\n\n';
prompt += 'SUMMARY STYLE: ' + style + '\n';
prompt += styleInstructions + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "videoTitle": "title of the video",\n';
prompt += '  "channel": "channel name if found",\n';
prompt += '  "summary": "the main summary text",\n';
prompt += '  "keyTakeaways": ["takeaway1", "takeaway2", "takeaway3"],\n';
prompt += '  "topics": ["topic1", "topic2"],\n';
prompt += '  "quotes": ["notable quote 1"],\n';
prompt += '  "sentiment": "positive|neutral|negative|mixed",\n';
prompt += '  "targetAudience": "who would benefit from this video",\n';
prompt += '  "actionItems": ["action1", "action2"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { videoTitle: $.steps.extractContent.output.title || 'Unknown', channel: '', summary: raw, keyTakeaways: [], topics: [], quotes: [], sentiment: 'unknown', targetAudience: '', actionItems: [] }; }

const ai = $.steps.parseAI.output;
const url = $.input.youtubeUrl;
const videoId = $.steps.extractContent.output.videoId;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'YouTube Video Summary', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*<' + url + '|' + (ai.videoTitle || 'Video') + '>*' } });

const fields = [];
if (ai.channel) fields.push({ type: 'mrkdwn', text: '*Channel:*\n' + ai.channel });
if (ai.sentiment) fields.push({ type: 'mrkdwn', text: '*Tone:*\n' + ai.sentiment });
if (ai.targetAudience) fields.push({ type: 'mrkdwn', text: '*For:*\n' + ai.targetAudience });
if (fields.length > 0) blocks.push({ type: 'section', fields: fields.slice(0, 4) });

blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.keyTakeaways && ai.keyTakeaways.length > 0) {
  blocks.push({ type: 'divider' });
  let ktText = '*Key Takeaways:*\n';
  ai.keyTakeaways.slice(0, 7).forEach((kt, i) => { ktText += (i + 1) + '. ' + kt + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ktText.slice(0, 1800) } });
}

if (ai.actionItems && ai.actionItems.length > 0) {
  let aiText = '*Action Items:*\n';
  ai.actionItems.slice(0, 5).forEach((a, i) => { aiText += '- ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: aiText.slice(0, 1800) } });
}

if (ai.quotes && ai.quotes.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Notable Quote:*\n> ' + ai.quotes[0].slice(0, 500) } });
}

if (ai.topics && ai.topics.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '*Topics:* ' + ai.topics.slice(0, 6).join(' | ') }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI' }] });

const fallbackText = 'YouTube Summary: ' + (ai.videoTitle || 'Video') + ' - ' + (ai.summary || '').slice(0, 80);
return { blocks, fallbackText };
